using System.Globalization;
using Shortcodes;

namespace OrchardCore.Shortcodes.Providers;

public class LocaleShortcodeProvider : IShortcodeProvider
{
    public const string ShortCodeIdentifier = "locale";

    private static ValueTask<string> Empty => new(string.Empty);
    private static ValueTask<string> Null => new((string)null);

    public ValueTask<string> EvaluateAsync(string identifier, Arguments arguments, string content, Context context)
    {
        if (identifier != ShortCodeIdentifier)
        {
            return Null;
        }

        var language = arguments.NamedOrDefault("lang")?.ToLower();
        var argFallback = arguments.NamedOrAt("fallback", 1);

        // Default value of true for the fallback argument.
        var fallback = argFallback == null || Convert.ToBoolean(argFallback);
        var currentCulture = CultureInfo.CurrentUICulture;

        if (fallback)
        {
            // Fallback to parent culture, if the current culture is en-CA and the shortcode targets en, the html will be output.
            do
            {
                if (currentCulture.Name.Equals(language, StringComparison.OrdinalIgnoreCase))
                {
                    return ValueTask.FromResult(content);
                }

                currentCulture = currentCulture.Parent;
            }
            while (currentCulture != CultureInfo.InvariantCulture);
        }
        else
        {
            if (currentCulture.Name.Equals(language, StringComparison.OrdinalIgnoreCase))
            {
                return ValueTask.FromResult(content);
            }
        }

        return Empty;
    }
}

using OrchardCore.Sitemaps.Models;
using OrchardCore.Sitemaps.Services;

namespace OrchardCore.Sitemaps.Handlers;

public class CustomPathSitemapSourceUpdateHandler : ISitemapSourceUpdateHandler
{
    private readonly ISitemapManager _sitemapManager;

    public CustomPathSitemapSourceUpdateHandler(ISitemapManager sitemapManager)
    {
        _sitemapManager = sitemapManager;
    }

    public async Task UpdateSitemapAsync(SitemapUpdateContext context)
    {
        var sitemaps = (await _sitemapManager.LoadSitemapsAsync()).Where(s => s.GetType() == typeof(Sitemap));

        if (!sitemaps.Any())
        {
            return;
        }

        var sitemapNeedsUpdate = false;

        foreach (var sitemap in sitemaps)
        {
            // Do not break out of this loop, as it must check each sitemap.
            foreach (var source in sitemap.SitemapSources
                .Select(s => s as CustomPathSitemapSource))
            {
                if (source == null)
                {
                    continue;
                }

                sitemap.Identifier = IdGenerator.GenerateId();
                sitemapNeedsUpdate = true;
            }
        }

        if (sitemapNeedsUpdate)
        {
            await _sitemapManager.UpdateSitemapAsync();
        }
    }
}

